const input = $input.first().json;
const settingsData = input;
let twilioNumber = "";
try { twilioNumber = $("Twilio: Purchase Phone Number").first().json.phone_number || ""; } catch (e) {}
const phoneRaw = settingsData.agent_phone_number || twilioNumber || input.agent_phone_number || input.twilio_number || input.phone_number || "";
const phone = String(phoneRaw);
const companyName = settingsData.company_name || input.company_name || "Your Company";
const agentName = settingsData.agent_name || input.agent_name || "AI Receptionist";
const leadEmail = settingsData.lead_email || input.lead_email || input.email || "";
if (!phone) { return [{ json: { ...input, emailHtml: "<p>No phone number configured.</p>", skipEmail: true, lead_email: leadEmail, company_name: companyName } }]; }
const digits = phone.replace(/[^0-9]/g, "");
let displayNum = phone;
if (digits.length === 11 && digits[0] === "1") { displayNum = "+" + digits[0] + " (" + digits.slice(1,4) + ") " + digits.slice(4,7) + "-" + digits.slice(7); } else if (digits.length === 10) { displayNum = "(" + digits.slice(0,3) + ") " + digits.slice(3,6) + "-" + digits.slice(6); }
function qr(code) { return "https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=" + encodeURIComponent("tel:" + code); }
const html = "<html><body><p>Welcome email for " + companyName + " - " + displayNum + "</p></body></html>";
return [{ json: { ...input, emailHtml: html, lead_email: leadEmail, company_name: companyName, agent_name: agentName, skipEmail: false } }];

